sys_ws_operation.operation_script:
(function process( /*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    // implement resource here
    var movieIdQP = request.queryParams.movieId;

    var watchListArr = [];

    var grWatchList = new GlideRecord('x_1962882_show_s_0_my_watchlist');
    if (movieIdQP) {
        grWatchList.addQuery('id', movieIdQP);
    }
    grWatchList.query();
    if (!grWatchList.hasNext()) {
        response.setError(new sn_ws_err.NotFoundError("No records found"));
        response.setStatus(404);
        return;
    }

    while (grWatchList.next()) {
        var watchListObj = {
            "Name": grWatchList.getDisplayValue('name'),
            "Genre": grWatchList.getDisplayValue('genres'),
            "Id": grWatchList.getDisplayValue('id'),
            "Overview": grWatchList.getDisplayValue('overview'),
            "Rating": grWatchList.getDisplayValue('rating'),
            "Release Date": grWatchList.getDisplayValue('release_date'),
            "Poster": grWatchList.getDisplayValue('poster')
        };
        watchListArr.push(watchListObj);
    }

    response.setBody(watchListArr);


})(request, response);
